<?php namespace App\Domains\RealEstateSales\Policies; use Illuminate\Auth\Access\HandlesAuthorization; class SalesPolicy { use HandlesAuthorization; public function viewAny($user) { return true; } public function view($user, $sale) { return $user->tenant_id === $sale->tenant_id; } public function create($user) { return true; } public function update($user, $sale) { return $user->tenant_id === $sale->tenant_id; } public function delete($user, $sale) { return $user->tenant_id === $sale->tenant_id; } }
